  done_at timestamptz,
  done_by uuid references auth.users(id),
  blocked_reason text,
  output_notes text,                      -- deliverable yang diharapkan
  source public.action_source not null default 'onboarding',
  source_ref text,                        -- mis. "Onboarding 30 Mar 2026 R1"
  created_at timestamptz not null default now(),
  created_by uuid references auth.users(id),
  updated_at timestamptz not null default now()
);
create index if not exists idx_supaction_sup on public.supplier_actions(supplier_id);
create index if not exists idx_supaction_status on public.supplier_actions(status);
create index if not exists idx_supaction_prio on public.supplier_actions(priority, target_date);
create index if not exists idx_supaction_target on public.supplier_actions(target_date) where status in ('open','in_progress','blocked');

