-- ============================================================================
-- RPC: Convert quotation → Purchase Order
-- Ambil harga & qty final (quoted) dari quotation_rows → buat PO baru, lock
-- quotation ke status='converted' + set converted_po_no.
-- ============================================================================
create or replace function public.convert_quotation_to_po(p_qt_no text)
returns text
language plpgsql security definer
set search_path = public, auth
as $$
declare
  v_qt record;
  v_po_no text;
  v_year text;
  v_seq int;
  v_line smallint := 1;
  v_total numeric(14,2) := 0;
  r record;
begin
  if public.current_role() not in ('admin','operator') then
    raise exception 'forbidden';
  end if;

  select * into v_qt from public.quotations where no = p_qt_no;
  if not found then
    raise exception 'quotation % not found', p_qt_no;
  end if;
  if v_qt.status = 'converted' and v_qt.converted_po_no is not null then
    return v_qt.converted_po_no;  -- idempotent
  end if;
  if v_qt.status not in ('accepted','responded') then
    raise exception 'quotation % status % cannot be converted', p_qt_no, v_qt.status;
  end if;

  v_year := to_char(current_date, 'YYYY');
  select coalesce(max(
    nullif(regexp_replace(no, 'PO-' || v_year || '-', ''), '')::int
  ), 0) + 1
  into v_seq
  from public.purchase_orders
  where no like 'PO-' || v_year || '-%';
  v_po_no := 'PO-' || v_year || '-' || lpad(v_seq::text, 3, '0');

  insert into public.purchase_orders(
    no, po_date, supplier_id, delivery_date, status, notes, created_by
  ) values (
    v_po_no, current_date, v_qt.supplier_id, v_qt.need_date, 'draft',
    'Dari ' || p_qt_no || coalesce(' · ' || v_qt.notes, ''),
    auth.uid()
  );

  for r in
    select
      item_code,
      unit,
      coalesce(qty_quoted, qty) as qty_final,
      coalesce(price_quoted, price_suggested, 0) as price_final
    from public.quotation_rows
    where qt_no = p_qt_no
    order by line_no
  loop
    insert into public.po_rows(po_no, line_no, item_code, qty, unit, price)
    values (v_po_no, v_line, r.item_code, r.qty_final, r.unit, r.price_final);
    v_total := v_total + r.qty_final * r.price_final;
    v_line := v_line + 1;
  end loop;

  update public.purchase_orders set total = v_total where no = v_po_no;

  update public.quotations
    set status = 'converted', converted_po_no = v_po_no
    where no = p_qt_no;

  return v_po_no;
end; $$;

grant execute on function public.convert_quotation_to_po(text) to authenticated;

-- ============================================================================
-- RPC: Pre-fill quotation rows dari requirement_for_date
-- Dipakai UI untuk seed items berdasarkan menu di tanggal tertentu.
-- ============================================================================
create or replace function public.quotation_seed_from_date(
  p_date date
)
returns table(item_code text, qty numeric, unit text, price_suggested numeric)
language sql stable as $$
  select
    r.item_code,
    round(r.qty::numeric, 3) as qty,
    r.unit,
    coalesce(
      -- saran harga = last PO price dari item ini (semua supplier)
      (select pr.price
         from public.po_rows pr
         join public.purchase_orders po on po.no = pr.po_no
         where pr.item_code = r.item_code
         order by po.po_date desc
         limit 1),
      -- fallback: price_idr dari BOM/items catalog
      r.price_idr
    ) as price_suggested
  from public.requirement_for_date(p_date) r
  order by r.item_code;
$$;

grant execute on function public.quotation_seed_from_date(date) to authenticated;


-- >>> 0011_grn_autostock.sql ================================================
-- ============================================================================
-- 0011 · GRN → Stock auto-sync
-- Saat GRN di-mark status='ok', otomatis iterasi po_rows untuk generate
-- stock_moves (reason='receipt'). trg_moves_apply existing akan update stock.
-- Idempotent: cek dulu kalau sudah ada stock_moves dengan ref_doc='grn' dan
-- ref_no=GRN.no — kalau ada, skip (jangan double-insert).
-- Untuk status='partial', qty tetap dipakai full dari po_rows (approximation);
-- operator bisa manual adjustment lewat stock_moves kalau ada selisih real.
-- Untuk status='rejected' → tidak insert apapun.
-- ============================================================================

create or replace function public.grn_sync_stock()
returns trigger language plpgsql as $$
declare
  v_exists int;
  v_po text;
  r record;
begin
  -- Hanya kalau transisi ke 'ok' atau 'partial'
  if new.status not in ('ok','partial') then
    return new;
  end if;
  -- Skip kalau status lama sudah ok/partial (tidak re-sync)
  if tg_op = 'UPDATE' and old.status in ('ok','partial') then
    return new;
  end if;

  v_po := new.po_no;
  if v_po is null then
    return new;
  end if;

  -- Idempotency guard: sudah pernah insert stock_moves untuk GRN ini?
  select count(*) into v_exists
    from public.stock_moves
    where ref_doc = 'grn' and ref_no = new.no;
  if v_exists > 0 then
    return new;
  end if;

  for r in
    select item_code, qty, unit
      from public.po_rows
      where po_no = v_po
      order by line_no
  loop
    insert into public.stock_moves(
      item_code, delta, reason, ref_doc, ref_no, note, created_by
    ) values (
      r.item_code,
      r.qty,          -- qty positif = masuk stock
      'receipt',
      'grn',
      new.no,
      'Auto-sync dari GRN ' || new.no || ' (PO ' || v_po || ')',
      auth.uid()
    );
  end loop;

  return new;
end; $$;

drop trigger if exists trg_grn_sync_stock_ins on public.grns;
drop trigger if exists trg_grn_sync_stock_ins on public.grns;
create trigger trg_grn_sync_stock_ins after insert on public.grns
  for each row execute function public.grn_sync_stock();

drop trigger if exists trg_grn_sync_stock_upd on public.grns;
drop trigger if exists trg_grn_sync_stock_upd on public.grns;
create trigger trg_grn_sync_stock_upd after update of status on public.grns
  for each row execute function public.grn_sync_stock();

-- ----------------------------------------------------------------------------
-- Optional: saat PO di-deliver, auto-set status.
-- ----------------------------------------------------------------------------
create or replace function public.po_mark_delivered_on_grn()
returns trigger language plpgsql as $$
begin
  if new.status in ('ok','partial') and new.po_no is not null then
    update public.purchase_orders
      set status = 'delivered'
      where no = new.po_no
        and status in ('draft','sent','confirmed');
  end if;
  return new;
end; $$;

drop trigger if exists trg_po_delivered_from_grn on public.grns;
drop trigger if exists trg_po_delivered_from_grn on public.grns;
create trigger trg_po_delivered_from_grn after insert or update of status on public.grns
  for each row execute function public.po_mark_delivered_on_grn();


