-- >>> 0018_strip_buah_prefix.sql ============================================
-- =============================================================================
-- 0018 · Strip "Buah - " prefix dari items.code (+ cascade ke semua FK children)
-- -----------------------------------------------------------------------------
-- Background: seed awal pakai code 'Buah - Pisang', 'Buah - Pepaya', dll untuk
-- grouping visual. Display sekarang minta code bersih ('Pisang', 'Pepaya', ...).
-- Migrasi ini rename items.code + propagate ke semua tabel anak via dynamic
-- drop/update/re-add FK (karena FK existing tidak pakai ON UPDATE CASCADE).
--
-- Idempoten: aman re-run — kalau tidak ada lagi row yang match 'Buah - %',
-- loop update jadi no-op.
-- =============================================================================

do $$
declare
  fk record;
  v_delete_rule text;
  v_update_rule text;
begin
  -- Kalau tidak ada lagi items dengan prefix 'Buah - ', skip (idempotency).
  if not exists (select 1 from public.items where code like 'Buah - %') then
    return;
  end if;

  -- Loop semua FK constraint yang reference public.items(code), drop dulu,
  -- update kolom anak, lalu re-add dengan aturan delete/update yang sama.
  for fk in
    select
      tc.table_schema,
      tc.table_name,
      tc.constraint_name,
      kcu.column_name,
      rc.delete_rule,
      rc.update_rule
    from information_schema.table_constraints tc
    join information_schema.key_column_usage kcu
      on kcu.constraint_name = tc.constraint_name
     and kcu.table_schema    = tc.table_schema
    join information_schema.referential_constraints rc
      on rc.constraint_name   = tc.constraint_name
     and rc.constraint_schema = tc.constraint_schema
    join information_schema.constraint_column_usage ccu
      on ccu.constraint_name   = rc.unique_constraint_name
     and ccu.constraint_schema = rc.unique_constraint_schema
    where tc.constraint_type = 'FOREIGN KEY'
      and ccu.table_schema   = 'public'
      and ccu.table_name     = 'items'
      and ccu.column_name    = 'code'
  loop
    v_delete_rule := case fk.delete_rule
      when 'CASCADE'     then 'cascade'
      when 'SET NULL'    then 'set null'
      when 'SET DEFAULT' then 'set default'
      when 'RESTRICT'    then 'restrict'
      else 'no action'
    end;
    v_update_rule := case fk.update_rule
      when 'CASCADE'     then 'cascade'
      when 'SET NULL'    then 'set null'
      when 'SET DEFAULT' then 'set default'
      when 'RESTRICT'    then 'restrict'
      else 'no action'
    end;

    execute format(
      'alter table %I.%I drop constraint %I',
      fk.table_schema, fk.table_name, fk.constraint_name
    );

    execute format(
      'update %I.%I set %I = regexp_replace(%I, ''^Buah - '', '''') where %I like ''Buah - %%''',
      fk.table_schema, fk.table_name, fk.column_name, fk.column_name, fk.column_name
    );

    execute format(
      'alter table %I.%I add constraint %I foreign key (%I) references public.items(code) on delete %s on update %s',
      fk.table_schema, fk.table_name, fk.constraint_name, fk.column_name,
      v_delete_rule, v_update_rule
    );
  end loop;

  -- Terakhir, rename di parent (items.code itu sendiri).
  update public.items
     set code = regexp_replace(code, '^Buah - ', '')
   where code like 'Buah - %';
end$$;

-- Bonus cleanup: kolom deskripsi bebas yang menyebut 'Buah - X' secara literal.
update public.suppliers
   set commodity = regexp_replace(commodity, 'Buah - ', '', 'g')
 where commodity like '%Buah - %';


-- >>> 0018_supplier_forecast.sql ============================================
-- =============================================================================
-- 0018 · Supplier 90-day Forecast (limited-access portal)
-- -----------------------------------------------------------------------------
-- Kebutuhan: supplier boleh lihat forecast kebutuhan per komoditas sampai 3
-- bulan ke depan, tapi HANYA untuk item yang dia jual (supplier_items),
-- dan tanpa bocor harga/supplier lain.
--
-- Sumber data tanggal:
--   1. custom_menus(menu_date)    → flatten (source='custom')
--   2. menu_assign(assign_date)   → BOM menu (source='assigned')
--   3. fallback → cycle rotation dari settings.go_live_date + active_cycle_days
--      (source='cycle')
--
-- Weekend & non_op_days → skip.
-- =============================================================================

-- Projected requirement untuk tanggal apapun (pakai cycle fallback)
create or replace function public.requirement_for_date_projected(p_date date)
returns table(
  item_code text,
  qty numeric,
  unit text,
  category public.item_category,
  source text  -- 'assigned' | 'cycle' | 'custom'
)
language plpgsql stable as $$
declare
  v_menu smallint;
  v_source text := 'assigned';
  v_tier record;
  v_cycle_days int;
  v_go_live date;
  v_cycle_day int;
  v_offset int;
begin
  -- Weekend skip
  if extract(dow from p_date) in (0,6) then return; end if;
  -- Non-op skip
  if exists (select 1 from public.non_op_days where op_date = p_date) then return; end if;

  -- Custom menu (flat 100g/porsi per item)
  if exists (select 1 from public.custom_menus where menu_date = p_date) then
    declare v_eff numeric := public.porsi_effective(p_date);
    begin
      if v_eff <= 0 then return; end if;
      return query
        select
          it.code as item_code,
          (100.0 * v_eff / 1000.0)::numeric as qty,
          it.unit,
          it.category,
          'custom'::text as source
        from public.custom_menus cm,
             jsonb_array_elements_text(cm.karbo || cm.protein || cm.sayur || cm.buah) as elem(val)
             join public.items it on it.code = elem.val
        where cm.menu_date = p_date;
      return;
    end;
  end if;

  -- Assigned?
  select menu_id into v_menu from public.menu_assign where assign_date = p_date;

  if v_menu is null then
    -- Cycle fallback
    select nullif(trim(both '"' from value::text), '')::int
      into v_cycle_days
      from public.settings where key = 'active_cycle_days';
    select nullif(trim(both '"' from value::text), '')::date
      into v_go_live
      from public.settings where key = 'go_live_date';

    v_cycle_days := coalesce(v_cycle_days, 14);
    v_go_live    := coalesce(v_go_live, date '2026-05-04');

    v_offset := (p_date - v_go_live)::int;
    -- Python-style positive modulo untuk handle date < go_live
    v_cycle_day := ((v_offset % v_cycle_days) + v_cycle_days) % v_cycle_days + 1;

    select id into v_menu
      from public.menus
      where cycle_day = v_cycle_day and active = true
      order by id
      limit 1;

    if v_menu is null then return; end if;
    v_source := 'cycle';
  end if;

  -- Porsi tiered
  select paud, sd13, sd46, smp_plus, operasional
    into v_tier from public.porsi_counts_tiered(p_date);
  if not coalesce(v_tier.operasional, false) then return; end if;

  return query
    select
      b.item_code,
      (
        case
          when (coalesce(b.grams_paud,0) + coalesce(b.grams_sd13,0)
              + coalesce(b.grams_sd46,0) + coalesce(b.grams_smp,0)) > 0 then
            (coalesce(b.grams_paud,0) * v_tier.paud
           + coalesce(b.grams_sd13,0) * v_tier.sd13
           + coalesce(b.grams_sd46,0) * v_tier.sd46
           + coalesce(b.grams_smp,0)  * v_tier.smp_plus) / 1000.0
          else
            b.grams_per_porsi * public.porsi_effective(p_date) / 1000.0
        end
      )::numeric as qty,
      it.unit,
      it.category,
      v_source as source
    from public.menu_bom b
    join public.items it on it.code = b.item_code
    where b.menu_id = v_menu;
end; $$;

grant execute on function public.requirement_for_date_projected(date) to authenticated;

-- =============================================================================
-- RPC · supplier_forecast_90d
-- Return daily forecast per item yang ada di supplier_items(supplier_id).
-- Supplier-role: force ke own supplier_id. Staff: bebas (atau fallback ke
-- parameter supplier_id).
-- =============================================================================
create or replace function public.supplier_forecast_90d(
  p_supplier_id text default null,
  p_horizon_days int default 90
)
returns table(
  op_date date,
  item_code text,
  item_name text,
  unit text,
  category public.item_category,
  qty numeric,
  source text
)
language plpgsql stable
security definer
set search_path = public, auth
as $$
declare
  v_sup text;
  v_role public.user_role;
  v_horizon int;
begin
  v_role := public.current_role();
  v_horizon := greatest(1, least(coalesce(p_horizon_days, 90), 180));

  if v_role = 'supplier' then
    v_sup := public.current_supplier_id();
    if v_sup is null then raise exception 'supplier profile incomplete'; end if;
  elsif v_role in ('admin','operator','ahli_gizi','viewer') then
    v_sup := coalesce(p_supplier_id, public.current_supplier_id());
    if v_sup is null then
      raise exception 'supplier_id required';
    end if;
  else
    raise exception 'forbidden';
  end if;

  return query
    select
      (d::date) as op_date,
      r.item_code,
      coalesce(it.name_en, r.item_code) as item_name,
      r.unit,
      r.category,
      round(r.qty, 3) as qty,
      r.source
    from generate_series(
      current_date, current_date + (v_horizon - 1), interval '1 day'
    ) as d
    cross join lateral public.requirement_for_date_projected(d::date) r
    join public.items it on it.code = r.item_code
    where exists (
      select 1 from public.supplier_items si
      where si.supplier_id = v_sup and si.item_code = r.item_code
    )
      and r.qty > 0
    order by d, r.item_code;
end; $$;

grant execute on function public.supplier_forecast_90d(text, int) to authenticated;

-- =============================================================================
-- RPC · supplier_forecast_monthly (agregasi 3 bulan per item)
-- Return: bulan × item → total_qty, dipakai di tab "Monthly"
-- =============================================================================
create or replace function public.supplier_forecast_monthly(
  p_supplier_id text default null,
  p_months int default 3
)
returns table(
  month date,
  item_code text,
  item_name text,
  unit text,
  category public.item_category,
  qty_total numeric,
  days_count int
)
language plpgsql stable
security definer
set search_path = public, auth
as $$
declare
  v_sup text;
  v_role public.user_role;
  v_months int;
  v_horizon int;
begin
  v_role := public.current_role();
  v_months := greatest(1, least(coalesce(p_months, 3), 6));
  v_horizon := v_months * 31;

  if v_role = 'supplier' then
    v_sup := public.current_supplier_id();
    if v_sup is null then raise exception 'supplier profile incomplete'; end if;
  elsif v_role in ('admin','operator','ahli_gizi','viewer') then
    v_sup := coalesce(p_supplier_id, public.current_supplier_id());
    if v_sup is null then raise exception 'supplier_id required'; end if;
  else
    raise exception 'forbidden';
  end if;

  return query
    select
      date_trunc('month', d::date)::date as month,
      r.item_code,
      coalesce(it.name_en, r.item_code) as item_name,
      r.unit,
      r.category,
      round(sum(r.qty), 3) as qty_total,
      count(*)::int as days_count
    from generate_series(
      current_date, current_date + (v_horizon - 1), interval '1 day'
    ) as d
    cross join lateral public.requirement_for_date_projected(d::date) r
    join public.items it on it.code = r.item_code
    where exists (
      select 1 from public.supplier_items si
      where si.supplier_id = v_sup and si.item_code = r.item_code
    )
      and r.qty > 0
      and (date_trunc('month', d::date) < date_trunc('month', current_date)
           + (v_months || ' months')::interval)
    group by date_trunc('month', d::date), r.item_code, it.name_en, r.unit, r.category
    order by date_trunc('month', d::date), r.item_code;
end; $$;

grant execute on function public.supplier_forecast_monthly(text, int) to authenticated;


-- >>> 0019_rls_align_calendar_writers.sql ===================================
-- =============================================================================
-- 0019 · Align RLS write policies with calendar UI role matrix
-- -----------------------------------------------------------------------------
-- Problem: app/calendar/page.tsx menganggap ahli_gizi boleh menulis ke tabel
-- planning (`non_op_days`, `school_attendance` via CalendarGrid), tapi RLS
-- policy hanya allow admin/operator. Hasilnya tombol "Tandai Non-Op" /
-- upsert kehadiran siswa terlihat di UI lalu ditolak DB:
--   "new row violates row-level security policy for table non_op_days"
--
-- Fix: rewrite write policy untuk 2 tabel supaya include ahli_gizi.
-- Read policy tidak berubah. Idempoten (drop-create). Tidak mengubah semantik
-- tabel operasional lain (stock, PO, GRN, invoice, receipt, tx) — mereka
-- tetap admin/operator only karena bukan ranah ahli_gizi.
-- =============================================================================

-- -----------------------------------------------------------------------------
-- non_op_days · shared planning surface (kalender menu)
-- -----------------------------------------------------------------------------
drop policy if exists "nonop: op/admin write" on public.non_op_days;
drop policy if exists "nonop: op/gz/admin write" on public.non_op_days;
drop policy if exists "nonop: op/gz/admin write" on public.non_op_days;
create policy "nonop: op/gz/admin write" on public.non_op_days
  for all using (public.current_role() in ('admin','operator','ahli_gizi'))
  with check (public.current_role() in ('admin','operator','ahli_gizi'));

-- -----------------------------------------------------------------------------
-- school_attendance · diisi dari calendar-grid (forecast harian)
-- -----------------------------------------------------------------------------
drop policy if exists "sch_att: operator write" on public.school_attendance;
drop policy if exists "sch_att: op/gz/admin write" on public.school_attendance;
drop policy if exists "sch_att: op/gz/admin write" on public.school_attendance;
create policy "sch_att: op/gz/admin write" on public.school_attendance
  for all using (public.current_role() in ('admin','operator','ahli_gizi'))
  with check (public.current_role() in ('admin','operator','ahli_gizi'));

-- =============================================================================
-- END 0019
-- =============================================================================


commit;


-- =============================================================================
-- 0018 · Price List RPC helpers
-- =============================================================================
begin;

-- =============================================================================
-- 0018 · Weekly Price List · RPC helpers (upsert + bulk import)
-- -----------------------------------------------------------------------------
-- 1) upsert_supplier_price   : satu sel edit dari grid Next.js
-- 2) import_price_list_json  : bulk import dari HTML dashboard localStorage
--                              (format: STATE.priceList dump)
-- 3) set_items_price_from_latest : sync items.price_idr dari minggu terbaru
--
-- Semua RPC pakai role user (bukan SECURITY DEFINER) → RLS policies 0017
-- yang menentukan siapa boleh write.
-- =============================================================================

-- -----------------------------------------------------------------------------
-- 1. upsert_supplier_price
-- -----------------------------------------------------------------------------
create or replace function public.upsert_supplier_price(
  p_week_id         bigint,
  p_supplier_id     text,
  p_commodity       public.price_commodity,
  p_ingredient_name text,
  p_price_per_kg    numeric(14,2) default null,
  p_price_per_item  numeric(14,2) default null,
  p_unit            text default 'kg',
  p_item_code       text default null,
  p_notes           text default null
)
returns public.supplier_prices
language plpgsql
as $$
declare
  v_row public.supplier_prices;
begin
  -- Guard: minimal satu harga harus ada
  if p_price_per_kg is null and p_price_per_item is null then
    -- null semua → interpret sebagai "clear cell" (delete)
    delete from public.supplier_prices
     where week_id = p_week_id
       and supplier_id = p_supplier_id
       and commodity = p_commodity
       and ingredient_name = p_ingredient_name
    returning * into v_row;
    return v_row;
  end if;

  insert into public.supplier_prices (
    week_id, supplier_id, commodity, ingredient_name,
    item_code, price_per_kg, price_per_item, unit, notes, created_by
  )
  values (
    p_week_id, p_supplier_id, p_commodity, p_ingredient_name,
    p_item_code, p_price_per_kg, p_price_per_item, coalesce(p_unit,'kg'),
    p_notes, auth.uid()
  )
  on conflict (week_id, supplier_id, commodity, ingredient_name)
  do update set
    price_per_kg   = excluded.price_per_kg,
    price_per_item = excluded.price_per_item,
    unit           = excluded.unit,
    item_code      = coalesce(excluded.item_code, supplier_prices.item_code),
    notes          = coalesce(excluded.notes, supplier_prices.notes),
    updated_at     = now()
  returning * into v_row;

  return v_row;
end;
$$;

grant execute on function public.upsert_supplier_price(
  bigint, text, public.price_commodity, text,
  numeric, numeric, text, text, text
) to authenticated;

-- -----------------------------------------------------------------------------
-- 2. import_price_list_json
-- -----------------------------------------------------------------------------
-- Input shape (matches STATE.priceList di HTML dashboard):
-- [
--   {
--     "commodity":"BERAS", "ingredient":"Beras Premium",
--     "supplier":"UD Karya Sukses", "unit":"kg",
--     "pricePerItem": null,
--     "weekly":[12000,12100,12200,null,null,null,null,null,null,null,null,null],
--     "notes":""
--   }, ...
-- ]
-- Plus p_period_id target. Supplier name akan di-resolve ke suppliers.id via
-- lower(name) match; kalau nggak ketemu → skip row dan laporkan di summary.
-- -----------------------------------------------------------------------------
create or replace function public.import_price_list_json(
  p_period_id smallint,
  p_payload   jsonb
)
returns table (
  rows_processed int,
  cells_upserted int,
  suppliers_missing text[]
)
language plpgsql
as $$
declare
  v_row jsonb;
  v_week_row record;
  v_weeks bigint[];
  v_supplier_id text;
  v_price numeric;
  v_missing text[] := array[]::text[];
  v_rows_cnt int := 0;
  v_cells_cnt int := 0;
  v_weekly jsonb;
  v_commodity public.price_commodity;
  i int;
begin
  -- Pre-fetch week ids urutan week_no
  select array_agg(id order by week_no) into v_weeks
  from public.price_weeks
  where period_id = p_period_id;

  if v_weeks is null or array_length(v_weeks,1) is null then
    raise exception 'Period % belum punya week rows', p_period_id;
  end if;

  for v_row in select * from jsonb_array_elements(p_payload)
  loop
    v_rows_cnt := v_rows_cnt + 1;

    -- Resolve supplier by name (case-insensitive)
    select id into v_supplier_id
    from public.suppliers
    where lower(name) = lower(v_row->>'supplier')
    limit 1;

    if v_supplier_id is null then
      v_missing := array_append(v_missing, v_row->>'supplier');
      continue;
    end if;

    -- Cast commodity
    begin
      v_commodity := (v_row->>'commodity')::public.price_commodity;
    exception when others then
      continue; -- skip invalid commodity
    end;

    v_weekly := v_row->'weekly';

    for i in 0..least(jsonb_array_length(v_weekly)-1, array_length(v_weeks,1)-1)
    loop
      if jsonb_typeof(v_weekly->i) = 'number' then
        v_price := (v_weekly->>i)::numeric;
        perform public.upsert_supplier_price(
          v_weeks[i+1],
          v_supplier_id,
          v_commodity,
          coalesce(v_row->>'ingredient',''),
          v_price,
          case when (v_row->>'pricePerItem') ~ '^[0-9.]+$'
               then (v_row->>'pricePerItem')::numeric else null end,
          coalesce(v_row->>'unit','kg'),
          null,
          nullif(v_row->>'notes','')
        );
        v_cells_cnt := v_cells_cnt + 1;
      end if;
    end loop;
  end loop;

  return query select v_rows_cnt, v_cells_cnt,
    (select array_agg(distinct m) from unnest(v_missing) m);
end;
$$;

grant execute on function public.import_price_list_json(smallint, jsonb) to authenticated;

-- -----------------------------------------------------------------------------
-- 3. items_price_from_latest
-- -----------------------------------------------------------------------------
-- Untuk setiap (commodity, ingredient_name) ambil median harga per-kg dari
-- minggu terbaru yang sudah ter-isi; pakai sebagai reference. Kembalikan tabel
-- supaya UI bisa preview dulu sebelum update master items.
-- -----------------------------------------------------------------------------
create or replace function public.price_list_latest_benchmark(p_period_id smallint)
returns table (
  commodity       public.price_commodity,
  ingredient_name text,
  latest_week_no  smallint,
  supplier_cnt    int,
  median_per_kg   numeric,
  min_per_kg      numeric,
  max_per_kg      numeric
)
language sql stable as $$
  with latest as (
    select sp.commodity, sp.ingredient_name, pw.week_no, sp.price_per_kg
    from public.supplier_prices sp
    join public.price_weeks pw on pw.id = sp.week_id
    where pw.period_id = p_period_id and sp.price_per_kg is not null
  ),
  per_group_latest as (
    select commodity, ingredient_name, max(week_no) as latest_week_no
    from latest
    group by commodity, ingredient_name
  )
  select l.commodity,
         l.ingredient_name,
         p.latest_week_no,
         count(*)::int                                                  as supplier_cnt,
         round(percentile_cont(0.5) within group (order by l.price_per_kg)::numeric, 2) as median_per_kg,
         min(l.price_per_kg)                                            as min_per_kg,
         max(l.price_per_kg)                                            as max_per_kg
  from latest l
  join per_group_latest p
    on p.commodity = l.commodity
   and p.ingredient_name = l.ingredient_name
   and p.latest_week_no = l.week_no
  group by l.commodity, l.ingredient_name, p.latest_week_no;
$$;

grant execute on function public.price_list_latest_benchmark(smallint) to authenticated;

-- =============================================================================
-- END 0018
-- =============================================================================

commit;


-- =============================================================================
-- 0019 · Storage buckets
-- =============================================================================
begin;

-- =============================================================================
-- 0019 · Storage Buckets · receipts + supplier_docs + avatars
-- -----------------------------------------------------------------------------
-- Bucket policies pakai storage.foldername(name) → path-prefix untuk per-supplier
-- isolation. Naming convention:
--   receipts/{yyyy-mm}/{tx_id}.{ext}        → nota pembelian/invoice (operator)
--   supplier_docs/{supplier_id}/{kind}.{ext} → cert, NIB, LTA (admin + supplier)
--   avatars/{user_id}.{ext}                  → profile pic (self)
--
-- RLS di storage.objects: Supabase sudah aktifkan by default. Kita cuma add
-- policies spesifik per bucket. Bucket dibuat via INSERT ke storage.buckets.
-- Idempotent: ON CONFLICT DO NOTHING.
-- =============================================================================

-- -----------------------------------------------------------------------------
-- 1. Buckets (private — tidak public browsable; akses via signed URL / policy)
-- -----------------------------------------------------------------------------
insert into storage.buckets (id, name, public, file_size_limit, allowed_mime_types)
values
  ('receipts',      'receipts',      false, 10485760, array['image/jpeg','image/png','image/webp','application/pdf']),
  ('supplier_docs', 'supplier_docs', false, 20971520, array['image/jpeg','image/png','application/pdf']),
  ('avatars',       'avatars',       true,   2097152, array['image/jpeg','image/png','image/webp'])
on conflict (id) do nothing;

-- -----------------------------------------------------------------------------
-- 2. Policies · RECEIPTS (operator write, semua auth read)
-- -----------------------------------------------------------------------------
drop policy if exists "receipts: auth read"   on storage.objects;
create policy "receipts: auth read" on storage.objects
  for select using (
    bucket_id = 'receipts'
    and auth.uid() is not null
  );

drop policy if exists "receipts: ops write"  on storage.objects;
create policy "receipts: ops write" on storage.objects
  for insert with check (
    bucket_id = 'receipts'
    and public.current_role() in ('admin','operator')
  );

drop policy if exists "receipts: ops update" on storage.objects;
create policy "receipts: ops update" on storage.objects
  for update using (
    bucket_id = 'receipts'
    and public.current_role() in ('admin','operator')
  );

drop policy if exists "receipts: admin delete" on storage.objects;
create policy "receipts: admin delete" on storage.objects
  for delete using (
    bucket_id = 'receipts'
    and public.is_admin()
  );

-- -----------------------------------------------------------------------------
-- 3. Policies · SUPPLIER_DOCS
--    Path: supplier_docs/{supplier_id}/{kind}.{ext}
--    - admin/operator: CRUD semua
--    - supplier role: CRUD hanya folder supplier_id mereka sendiri
--    - auth lain: read-only
-- -----------------------------------------------------------------------------
drop policy if exists "supplier_docs: auth read" on storage.objects;
create policy "supplier_docs: auth read" on storage.objects
  for select using (
    bucket_id = 'supplier_docs'
    and auth.uid() is not null
  );

drop policy if exists "supplier_docs: admin write" on storage.objects;
create policy "supplier_docs: admin write" on storage.objects
  for all using (
    bucket_id = 'supplier_docs'
    and public.current_role() in ('admin','operator')
  ) with check (
    bucket_id = 'supplier_docs'
    and public.current_role() in ('admin','operator')
  );

drop policy if exists "supplier_docs: supplier own write" on storage.objects;
create policy "supplier_docs: supplier own write" on storage.objects
  for all using (
    bucket_id = 'supplier_docs'
    and public.current_role() = 'supplier'
    and (storage.foldername(name))[1] = public.current_supplier_id()
  ) with check (
    bucket_id = 'supplier_docs'
    and public.current_role() = 'supplier'
    and (storage.foldername(name))[1] = public.current_supplier_id()
  );

-- -----------------------------------------------------------------------------
-- 4. Policies · AVATARS (public bucket, but write is self-only)
-- -----------------------------------------------------------------------------
drop policy if exists "avatars: public read" on storage.objects;
create policy "avatars: public read" on storage.objects
  for select using (bucket_id = 'avatars');

drop policy if exists "avatars: self write" on storage.objects;
create policy "avatars: self write" on storage.objects
  for all using (
    bucket_id = 'avatars'
    and (storage.foldername(name))[1] = auth.uid()::text
  ) with check (
    bucket_id = 'avatars'
    and (storage.foldername(name))[1] = auth.uid()::text
  );

-- =============================================================================
-- END 0019
-- =============================================================================

commit;
